def handle_get_product_by_id(product_id):
    try:
        product_id = int(product_id)
    except (ValueError, TypeError):
        return create_response(400, {
            'success': False,
            'error': 'Invalid product ID',
            'message': 'Product ID must be a valid integer'
        })

    try:
        conn = get_connection()
        query = "SELECT * FROM products WHERE id = %s"

        with conn.cursor() as cursor:
            cursor.execute(query, (product_id,))
            result = cursor.fetchone()

        if result is None:
            return create_response(404, {
                'success': False,
                'error': 'Product not found',
                'message': f'No product found with ID {product_id}'
            })

        serialized = serialize_results([result])[0]

        return create_response(200, {
            'success': True,
            'data': {
                'product': serialized
            }
        })

    except pymysql.MySQLError as e:
        logger.error(f"Database error fetching product {product_id}: {e}")
        return create_response(500, {
            'success': False,
            'error': 'Database error occurred',
            'message': str(e)
        })